// Get the day from webhook input
const day = $input.first().json.campaign_day;

// Import all day modules (simplified for n8n)
const days = {
  monday: {
    subject: "🍱 Meal Prep is Open — Fresh Bowls This Week",
    sms: "Meal prep is open 🍱 Orders close Wed 12:00 PM. order.theutopiadeli.com/catering/"
  },
  tuesday: {
    subject: "🎉 Planning an Event? Let's Cater It",
    sms: "Planning an event? 🎉 Catering from Utopia Deli. order.theutopiadeli.com/catering/"
  },
  wednesday: {
    subject: "⏰ Closes Today at Noon — Don't Miss This Week's Bowls",
    sms: "⏰ Meal prep closes today at noon! order.theutopiadeli.com/catering/"
  },
  thursday: {
    subject: "🍱 Meal Prep Reopens at 8PM + We're Open Today",
    sms: "Meal prep reopens at 8PM tonight! order.theutopiadeli.com/catering/"
  },
  friday: {
    subject: "🙌 Weekend at Utopia Deli",
    sms: "Weekend at Utopia Deli 🍽️ Order online: order.theutopiadeli.com/pickup-order/"
  },
  saturday: {
    subject: "🙌 We're Open Today — Come See Us!",
    sms: "We're open today! 🙌 Order ahead: order.theutopiadeli.com/pickup-order/"
  },
  sunday: {
    subject: "📋 This Week's Menu + Monday Lunch",
    sms: "This week's menu drops tomorrow at 9AM! order.theutopiadeli.com/catering/"
  }
};

if (!days[day]) {
  throw new Error('Invalid campaign_day: ' + day);
}

return [{
  json: {
    campaign_day: day,
    email_subject: days[day].subject,
    sms_body: days[day].sms
  }
}];

// Full email body generation
const day = $input.first().json.campaign_day;
const baseRepo = 'https://raw.githubusercontent.com/Phillip-Lowe/utopia-deli/main';
const baseURL = 'https://order.theutopiadeli.com';

// Image definitions per day
const images = {
  monday: [
    `${baseRepo}/Deli%20Meal%20Prep%20Plate%201.jpg`,
    `${baseRepo}/mealprep-mediterranean.jpg`,
    `${baseRepo}/mealprep-smokey-taco.jpg`,
    `${baseRepo}/mealprep-bbq-mac.jpg`,
    `${baseRepo}/cold_pressed_juice_v2.jpg`,
    `${baseRepo}/images/dessert-raspberry-mousse.jpg`
  ],
  tuesday: [
    `${baseRepo}/Deli%20Catering%20Salad.jpg`,
    `${baseRepo}/Deli%20Catering%20Fruit%20Salad.jpg`,
    `${baseRepo}/Deli%20Meal%20Prep%20Plate%201.jpg`
  ],
  wednesday: [
    `${baseRepo}/mealprep-smokey-taco.jpg`,
    `${baseRepo}/mealprep-chili-noodles.jpg`,
    `${baseRepo}/mealprep-peanut-tofu.jpg`
  ],
  thursday: [
    `${baseRepo}/Deli%20Meal%20Prep%20Plate%201.jpg`,
    `${baseRepo}/chicken_philly.jpg`,
    `${baseRepo}/loaded_bacon_fry.jpg`,
    `${baseRepo}/chicken_poppers_v3.jpg`
  ],
  friday: [
    `${baseRepo}/Deli%20Happy%20customer%20lady.jpg`,
    `${baseRepo}/chicken_philly.jpg`,
    `${baseRepo}/loaded_bacon_fry.jpg`,
    `${baseRepo}/chicken_poppers_v3.jpg`,
    `${baseRepo}/cookies_v2.jpg`,
    `${baseRepo}/cold_pressed_juice_v2.jpg`
  ],
  saturday: [
    `${baseRepo}/chicken_philly.jpg`,
    `${baseRepo}/chicken_poppers_v3.jpg`,
    `${baseRepo}/loaded_bacon_fry.jpg`,
    `${baseRepo}/cold_pressed_juice_v2.jpg`
  ],
  sunday: [
    `${baseRepo}/Deli%20Meal%20Prep%20Plate%201.jpg`,
    `${baseRepo}/chicken_philly.jpg`,
    `${baseRepo}/chicken_poppers_v3.jpg`
  ]
};

// Logo
const logo = `${baseRepo}/TheUtopiaDeliLogo.png`;

// Header builder
const buildHeader = () => \`<tr><td style=\"background:#590B3F;padding:20px 24px;\"><table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\"><tr><td style=\"vertical-align:middle;\"><img src=\"${logo}\" alt=\"The Utopia Deli\" style=\"height:56px;display:block;\"></td><td style=\"vertical-align:middle;padding-left:16px;\"><p style=\"margin:0;color:#fff;font-family:'Georgia','Times New Roman',serif;font-size:24px;font-weight:bold;letter-spacing:0.5px;\">The Utopia Deli</p></td></tr></table></td></tr>\`;

// Footer builder with working unsubscribe link
const buildFooter = () => \`<tr><td style=\"padding:20px;background:#f8f6f4;font-family:'Georgia','Times New Roman',serif;text-align:center;border-top:1px solid #e5e5e5;\"><p style=\"margin:0 0 6px;font-size:13px;color:#888;\">The Utopia Deli · 801 S Chester St · Little Rock, AR 72202</p><p style=\"margin:0;font-size:12px;\"><a href=\"https://n8n.systack.net/webhook/unsubscribe?email=%%EMAIL%%&channel=email\" style=\"color:#AF3D4B;text-decoration:underline;\">Unsubscribe from emails</a></p></td></tr>\`;

// Email wrapper
const wrapEmail = (content) => \`<!DOCTYPE html><html lang=\"en\"><head><meta charset=\"UTF-8\"><meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\"><style>@media only screen and (max-width: 600px) { .container { width: 100% !important; } .hero-img { height: 200px !important; } .dish-grid { display: block !important; } .dish-card { width: 100% !important; margin-bottom: 16px !important; } }</style></head><body style=\"margin:0;padding:0;background:#f8f6f4;font-family:'Georgia','Times New Roman',serif;\"><table width=\"100%\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\"><tr><td align=\"center\" style=\"padding:24px 12px;\"><table class=\"container\" width=\"600\" cellpadding=\"0\" cellspacing=\"0\" border=\"0\" style=\"background:#ffffff;border-radius:16px;overflow:hidden;max-width:600px;width:100%;\">${buildHeader()}${content}${buildFooter()}</table></td></tr></table></body></html>\`;

// Day-specific content (simplified for n8n import)
const dayContent = {
  monday: \`<tr><td><img src=\"${images.monday[0]}\" alt=\"Meal Prep\" class=\"hero-img\" style=\"width:100%;height:320px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">This Week's Meal Prep is Open 🍱</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Fresh, chef-crafted bowls ready for pickup. No cooking, no waiting — just heat and eat.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">⏰ Orders close Wednesday at 12:00 PM · Pickup Thursday</p><a href=\"${baseURL}/catering/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Get Your Meals</a></td></tr>\`,
  tuesday: \`<tr><td><img src=\"${images.tuesday[0]}\" alt=\"Catering\" class=\"hero-img\" style=\"width:100%;height:320px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">Planning an Event? Let's Make It Delicious 🎉</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Weddings, birthdays, celebrations — we cater events of all sizes.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">Minimum 10 guests · 3 days advance notice</p><a href=\"${baseURL}/catering/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Get a Catering Quote</a></td></tr>\`,
  wednesday: \`<tr><td><img src=\"${images.wednesday[0]}\" alt=\"Meal Prep Deadline\" class=\"hero-img\" style=\"width:100%;height:280px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;text-align:center;\"><h1 style=\"margin:0 0 16px;color:#AF3D4B;font-size:28px;line-height:1.2;\">Closes Today at 12:00 PM ⏰</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">This is your last chance to grab this week's meal prep. Fresh bowls, ready Thursday.</p><p style=\"margin:0 0 24px;color:#333;font-size:14px;\"><strong>Order before noon today</strong> — pickup Thursday 12:30 PM–7:30 PM</p><a href=\"${baseURL}/catering/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Secure My Bowls</a></td></tr>\`,
  thursday: \`<tr><td><img src=\"${images.thursday[0]}\" alt=\"Meal Prep Reopens\" class=\"hero-img\" style=\"width:100%;height:300px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">Meal Prep Orders Reopen at 8PM 🍱</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Tonight at 8:00 PM, the meal prep portal reopens for next week. Get your order in early.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">🕐 Reopens 8:00 PM tonight · Closes Wednesday at noon</p><a href=\"${baseURL}/catering/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Pre-Order Next Week's Bowls</a></td></tr>\`,
  friday: \`<tr><td><img src=\"${images.friday[0]}\" alt=\"Weekend at Utopia\" class=\"hero-img\" style=\"width:100%;height:320px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">Weekend at Utopia Deli 🍽️</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Friday feeling? We've got you covered. Walk-up orders, meal prep, and all your favorites are ready.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">🕐 Open today · Order online or walk up</p><a href=\"${baseURL}/pickup-order/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Order Now</a></td></tr>\`,
  saturday: \`<tr><td style=\"padding:32px 28px 20px;text-align:center;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">We're Open Today! 🙌</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Saturday at Utopia Deli — walk up or order online. Fresh food, good vibes.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">🕐 Open today · Order online or walk up</p><a href=\"${baseURL}/pickup-order/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">Order Ahead</a></td></tr>\`,
  sunday: \`<tr><td><img src=\"${images.sunday[0]}\" alt=\"This Week's Menu\" class=\"hero-img\" style=\"width:100%;height:300px;object-fit:cover;display:block;\"></td></tr><tr><td style=\"padding:32px 28px 20px;\"><h1 style=\"margin:0 0 16px;color:#590B3F;font-size:28px;line-height:1.2;\">This Week's Menu 📋</h1><p style=\"margin:0 0 20px;color:#333;font-size:16px;line-height:1.6;\">Meal prep orders open tomorrow at 9:00 AM. Here's what's cooking this week.</p><p style=\"margin:0 0 24px;color:#AF3D4B;font-size:15px;font-weight:bold;\">🍱 Meal prep opens Monday 9:00 AM · Closes Wednesday noon</p><a href=\"${baseURL}/catering/\" style=\"display:inline-block;background:#AF3D4B;color:#fff;padding:14px 32px;border-radius:10px;text-decoration:none;font-size:16px;font-weight:bold;\">View Full Menu</a></td></tr>\`
};

const emailBody = wrapEmail(dayContent[day] || dayContent.monday);

return [{
  json: {
    email_body: emailBody
  }
}];
